  ('diplomatic-ea72210e-moex-00134', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-113-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'essay', '國際法上的管轄權（jurisdiction）主要由國家所行使之，而關於國家的「域
外管轄」（extraterritorialjurisdiction）則時常產生爭議。試舉例說明並解
釋「域外管轄」所保護之利益及其可能與國際法衝突之處。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00135', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-113-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '依據維也納條約法公約，關於條約的解釋，下列敘述何者錯誤？', '["條約應以善意解釋之", "條約應按其上下文並參考其目的及宗旨解釋所具有之特殊意義解釋", "就解釋條約而言，上下文應包括弁言及附件", "就解釋條約而言，上下文應包括全體當事國間因締結條約所訂與條約有關之任何協定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00136', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-113-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '關於1969年維也納條約法公約規定，下列敘述何者錯誤？', '["依維也納條約法公約第 26 條之規定，凡有效之條約對其各當事國有拘束力，必須由各該國善 意履行", "依維也納條約法公約第 27 條規定，若有國內管轄原則之適用時，一當事國得援引其國內法規 定為理由而不履行條約", "依維也納條約法公約第28條之規定，除條約表示不同意思，或另經確定外，關於條約對一當事 國生效之日以前所發生之任何行為或事實或已不存在之任何情勢，條約之規定不對該當事國發 生拘束力", "依維也納條約法公約第29條之規定，除條約表示不同意思，或另經確定外，條約對每一當事國 之拘束力及於其全部領土"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00137', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-113-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '關於國際法主體，下列敘述何者正確？', '["政府間國際組織已成為最重要的國際法主體", "非自治領土均非國際法主體", "個人一定不是國際法主體", "民族解放運動得為國際法主體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00138', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-113-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '下列何者並非現存區域性人權條約所設之區域人權法院？', '["歐洲人權法院（EuropeanCourtofHumanRights）", "美洲人權法院（Inter-AmericanCourtofHumanRights）", "非洲人權和人民權利法院（AfricanCourtonHumanandPeople''sRights）", "亞洲人權法院（AsianCourtofHumanRights）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL),
  ('diplomatic-ea72210e-moex-00139', 'diplomatic-ea72210e', 'diplomatic-ea72210e-moex-113-10317cea', 'sub-diplomatic-ea72210e-02', NULL, 'single_choice', '依據國際法院規約第 38 條第 1 項規定，司法裁判為確定法律原則之補助資料。下列敘述何者正 確？', '["國際法院之裁判具有拘束所有國家之普遍效力", "國際法院規約第38條第1項規定之司法裁判係指國際爭端解決機制之裁決", "國際法院規約第38條第1項規定之司法裁判也包括國內法院裁判", "國際法院規約第38條第1項規定之司法裁判係指國際法院本身之判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:21:38+00:00", "source_pdf_sha1": "fce0585a3133", "answer_pdf_sha1": "3769d2d2ee5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-法文組"}'::jsonb, NULL)
